#include <stdio.h>
#include <string.h>

void trim_newline(char *s){
    size_t len = strlen(s);
    if(len>0 && s[len-1]=='\n') s[len-1]='\0';
}

int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    getchar(); // consume the newline after T
    char main_light[30];
    char blinking_light[30];
    for(int i=0;i<T;i++){
        if(!fgets(main_light, sizeof(main_light), stdin)) break;
        trim_newline(main_light);
        if(!fgets(blinking_light, sizeof(blinking_light), stdin)) break;
        trim_newline(blinking_light);
        if(strcmp(main_light, "red")==0 || strcmp(blinking_light, "flashing red")==0){
            puts("Stop");
        }else if(strcmp(main_light, "yellow")==0 || strcmp(blinking_light, "blinking yellow")==0){
            puts("Slow Down");
        }else if(strcmp(main_light, "green")==0 || strcmp(blinking_light, "blinking green")==0){
            puts("Go");
        }else{
            puts("Invalid input");
        }
    }
    return 0;
}

