code.Java:
import java.io.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if(line==null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for(int i=0;i<T;i++){
            String main = br.readLine();
            String blink = br.readLine();
            if(main==null) main=""; if(blink==null) blink="";
            if(main.equals("red") || blink.equals("flashing red"))
                sb.append("Stop");
            else if(main.equals("yellow") || blink.equals("blinking yellow"))
                sb.append("Slow Down");
            else if(main.equals("green") || blink.equals("blinking green"))
                sb.append("Go");
            else
                sb.append("Invalid input");
            if(i<T-1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

